        return map.get(key);
    }

    public void put(int key, int value) {
        if (map.containsKey(key)) {
            order.remove(Integer.valueOf(key));
        } else if (map.size() == capacity) {
            // Evict LRU (last element)
            // TODO: int lru = order.removeLast(); map.remove(lru);
        }
        // TODO: map.put(key, value); order.addFirst(key);
    }

    public static void main(String[] args) {
        LRUCache lru = new LRUCache(2);
        lru.put(1, 1);
        lru.put(2, 2);
        System.out.println("get(1): " + lru.get(1));   // 1 (now MRU)
        lru.put(3, 3);                                    // evicts key 2
        System.out.println("get(2): " + lru.get(2));   // -1 (evicted)
        lru.put(4, 4);                                    // evicts key 1
        System.out.println("get(1): " + lru.get(1));   // -1 (evicted)
        System.out.println("get(3): " + lru.get(3));   // 3
        System.out.println("get(4): " + lru.get(4));   // 4
    }
}

