import java.util.*;

public class DatabaseIndex {
    private Map<String, List<Integer>> index = new HashMap<>();
    private int rowId = 0;

    public int insert(String... values) {
        // values[0]=name, values[1]=dept, values[2]=salary
        // Index by first column (name) and second column (dept)
        // TODO: for column index 0 (name) and 1 (dept):
        //       index.computeIfAbsent(values[col]+":"+col, k->new ArrayList<>()).add(rowId)
        return rowId++;
    }

    public List<Integer> query(int col, String value) {
        return index.getOrDefault(value + ":" + col, Collections.emptyList());
    }

    public int cardinality(int col) {
        // TODO: count distinct keys for this column (keys ending with ":col")
        long c = index.keySet().stream().filter(k -> k.endsWith(":" + col)).count();
        return (int) c;
    }

    public static void main(String[] args) {
        DatabaseIndex db = new DatabaseIndex();
        db.insert("Alice", "Eng",  "90000");
        db.insert("Bob",   "HR",   "70000");
        db.insert("Carol", "Eng",  "80000");
        db.insert("Dave",  "Eng",  "75000");
        db.insert("Eve",   "HR",   "65000");

        System.out.println("Eng rows: " + db.query(1, "Eng"));
        System.out.println("HR rows:  " + db.query(1, "HR"));
        System.out.println("Alice rows: " + db.query(0, "Alice"));
        System.out.println("Name cardinality: " + db.cardinality(0));
        System.out.println("Dept cardinality: " + db.cardinality(1));
    }
}
